1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type Damage = { itemType: string; amount: number };
9	export type Incident = { cause: string; damages: Damage[] };
10	export type QuoteStep = { op: "quote"; items: Item[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	export type QuoteResult = { premium: number };
15	export type ClaimResult = { payout: number; remainingCap: number };
16	export type ScenarioResult = { results: (QuoteResult | ClaimResult)[] };
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	};
27	
28	const baseFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
29	
30	const quotePremium = (items: Item[]): number => {
31	  const itemsBase = items.reduce((sum, item) => sum + baseFor(item), 0);
32	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
33	  const total = itemsBase + firstInsurance + PROCESSING_FEE;
34	  return Math.ceil(total);
35	};
36	
37	export const runScenario = (scenario: Scenario): ScenarioResult => {
38	  const results = scenario.steps.map((step) => {
39	    if (step.op === "quote") return { premium: quotePremium(step.items) };
40	    return { payout: 0, remainingCap: 0 };
41	  });
42	  return { results };
43	};
